import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (request: ZuploRequest, context: ZuploContext) {
  // Clone the request so we can read the body for logging without consuming it
  const clonedRequest = request.clone();
  const requestBody = await clonedRequest.text();
  context.log.info(`Intercepted Request: ${requestBody}`);

  // Forward the original request to the upstream echo service
  const response = await fetch("http://127.0.0.1:8080/echo", {
    method: request.method,
    headers: request.headers,
    body: request.body,
  });

  // Clone the response so we can read the body for logging without consuming it
  const clonedResponse = response.clone();
  const responseBody = await clonedResponse.text();
  context.log.info(`Intercepted Response: ${responseBody}`);

  // Return the original response to the client
  return response;
}

